<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;
final class ApiAnalyticsController{
 public function index():void{Auth::requireRole('owner','administrator');$pdo=Database::connection();$summary=$pdo->query("SELECT COUNT(*) requests,SUM(response_status>=400) errors,ROUND(AVG(duration_ms),1) avg_ms,MAX(duration_ms) max_ms FROM api_usage_log WHERE created_at>=DATE_SUB(NOW(),INTERVAL 30 DAY)")->fetch();$daily=$pdo->query("SELECT DATE(created_at) day,COUNT(*) requests,SUM(response_status>=400) errors,ROUND(AVG(duration_ms),1) avg_ms FROM api_usage_log WHERE created_at>=DATE_SUB(CURDATE(),INTERVAL 29 DAY) GROUP BY DATE(created_at) ORDER BY day")->fetchAll();$tokens=$pdo->query("SELECT t.id,t.name,u.name user_name,COUNT(l.id) requests,SUM(l.response_status>=400) errors,ROUND(AVG(l.duration_ms),1) avg_ms,MAX(l.created_at) last_request_at FROM api_tokens t JOIN users u ON u.id=t.user_id LEFT JOIN api_usage_log l ON l.api_token_id=t.id AND l.created_at>=DATE_SUB(NOW(),INTERVAL 30 DAY) GROUP BY t.id,t.name,u.name ORDER BY requests DESC,t.name")->fetchAll();$paths=$pdo->query("SELECT request_method,request_path,COUNT(*) requests,SUM(response_status>=400) errors,ROUND(AVG(duration_ms),1) avg_ms FROM api_usage_log WHERE created_at>=DATE_SUB(NOW(),INTERVAL 30 DAY) GROUP BY request_method,request_path ORDER BY requests DESC LIMIT 25")->fetchAll();View::render('portal/api/analytics',['title'=>'API Analytics','summary'=>$summary,'daily'=>$daily,'tokens'=>$tokens,'paths'=>$paths],'portal');}
}
